const unique = (items) => [...new Set(items.filter(Boolean))];
const slugify = (value) => value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
const valueNote = (value, label) => value === null ? "Unknown — no verified dollar value is documented by the official source." : label ?? "Estimated value documented by the official source.";
const iconForType = (type) => ({ Scholarship: "scholarship", Research: "research", Career: "career", AI: "ai", Benefit: "benefit" })[type] ?? "career";
const defaultSkillsForType = (type) => ({
  Scholarship: ["Application Writing", "Planning"],
  Research: ["Research", "Technical Communication"],
  Career: ["Career Planning", "Professional Communication"],
  AI: ["Productivity", "Digital Research"],
  Benefit: ["Resourcefulness", "Budgeting"],
})[type] ?? ["Career Planning"];
const defaultCareerPathsForType = (type) => ({
  Scholarship: ["Funding"],
  Research: ["Research"],
  Career: ["Career Exploration"],
  AI: ["Student Productivity"],
  Benefit: ["Student Support"],
})[type] ?? ["Career Exploration"];

function record(input) {
  const id = `${prefix}${slugify(input.organization)}--${slugify(input.title)}`;
  const estimatedValue = input.estimatedValue ?? null;
  const tags = unique([
    input.category,
    input.type,
    input.organization,
    ...(input.tags ?? []),
    ...(input.majors ?? ["Any Major"]),
    ...(input.careerPaths ?? []),
    ...(input.skills ?? []),
    input.paid === true ? "Paid" : input.paid === false ? "Unpaid" : "",
    input.remote === true ? "Remote" : input.remote === false ? "In Person" : "",
    input.difficulty ?? "",
    input.applicationDeadline ? `Deadline ${input.applicationDeadline.slice(5, 7)}` : input.deadlineType === "rolling" ? "Rolling Deadline" : "Deadline Varies",
  ]);
  return {
    id,
    title: input.title,
    type: input.type,
    category: input.category,
    description: `${input.description} This matters because ${input.why}. ${input.audience} should review the official source, confirm current eligibility, and apply or claim through the provider's published process.`,
    organization: input.organization,
    school_scope: "National",
    schools: [],
    majors: input.majors ?? ["Any Major"],
    academic_years: input.academicYears ?? ["Any Year"],
    eligibility: input.eligibility,
    estimated_value: estimatedValue,
    application_deadline: input.applicationDeadline ?? null,
    recurring: input.recurring ?? true,
    location: input.location ?? "United States",
    remote: input.remote ?? null,
    paid: input.paid ?? null,
    tags,
    official_source: input.url,
    official_source_url: input.url,
    verification_status: input.verified ? "verified" : "needs_review",
    last_verified: verifiedAt,
    deadline: input.applicationDeadline ?? null,
    reviewer_notes: input.verified ? "Reviewed against an official source during the 2026 national opportunity expansion." : "Curated from an official provider domain; needs manual cycle-specific verification before being marked verified.",
    estimated_value_note: valueNote(estimatedValue, input.valueNote),
    date_added: verifiedAt,
    difficulty: input.difficulty ?? null,
    prestige: input.prestige ?? null,
    icon: input.icon ?? iconForType(input.type),
    featured: Boolean(input.featured),
    hidden_gem: Boolean(input.hiddenGem),
    metadata: {
      deadlineType: input.deadlineType ?? (input.applicationDeadline ? "fixed" : "varies"),
      claimUrl: input.url,
      verificationMethod: input.verified ? "Official source reviewed for this expansion." : "Official provider URL curated for manual verification.",
      compensation: input.compensation ?? (input.paid === true ? "Paid" : input.paid === false ? "Unpaid" : "Varies"),
      workMode: input.workMode ?? (input.remote === true ? "Remote" : input.remote === false ? "In Person" : "Varies"),
      awardAmountLabel: input.awardAmountLabel,
      renewable: input.renewable ?? null,
      applicationRequirements: input.applicationRequirements ?? [
        "Review the official provider page.",
        "Confirm current eligibility, deadline, citizenship, class-year, and document requirements.",
        "Apply or claim through the official application process.",
      ],
      ...(input.type === "Research" ? {
        department: input.department ?? input.organization,
        researchArea: input.researchArea ?? input.category,
        semesters: input.semesters ?? [input.applicationSeason ?? "Varies"],
        professor: input.professor ?? null,
        stipendAmount: input.stipendAmount ?? null,
      } : {}),
      eligibilityNotes: [input.eligibility, ...(input.eligibilityNotes ?? [])],
      reviewScore: input.verified ? 88 : 72,
      estimatedApplicationTime: input.estimatedApplicationTime ?? "Unknown",
      estimatedAcceptanceRate: input.estimatedAcceptanceRate ?? "Unknown",
      estimatedCompetitiveness: input.estimatedCompetitiveness ?? input.difficulty ?? "Unknown",
      applicationSeason: input.applicationSeason ?? "Varies",
      internshipDuration: input.internshipDuration,
      salaryEstimate: input.salaryEstimate,
      skillsGained: input.skills?.length ? input.skills : defaultSkillsForType(input.type),
      careerPaths: input.careerPaths?.length ? input.careerPaths : defaultCareerPathsForType(input.type),
      expectedROI: input.expectedROI ?? "Varies by student goals, eligibility, and completion.",
      recommendedMajors: input.majors ?? ["Any Major"],
      recommendedClassYears: input.academicYears ?? ["Any Year"],
      citizenship: input.citizenship ?? "Check official source",
      internationalEligibility: input.internationalEligibility ?? "Check official source",
      discountAmount: input.discountAmount,
      verificationRequired: input.verificationRequired,
      howToRedeem: input.howToRedeem,
      limitations: input.limitations,
      pricing: input.pricing,
      freeTier: input.freeTier,
      bestUseCases: input.bestUseCases,
    },
  };
}

